"""
Claude Code Adapter — generates CLAUDE.md + .claude/settings.json hooks

CLAUDE.md structure:
  [project header — written once on first create, never touched again]

  <!-- amk:start -->
  <!-- GENERATED by agent-memory-kit. DO NOT EDIT MANAGED BLOCK DIRECTLY. -->
  [generic memory protocol — updated by amk on regen]
  <!-- amk:end -->

  [anything the user adds below stays untouched]
"""
import json
import textwrap
from pathlib import Path

from .utils import (
    ensure_gitignored,
    write_managed_section,
    check_managed_section,
    check_fully_generated,
    GENERATED_BANNER_SH,
    mode_for,
)


MANAGED_CONTENT_TEMPLATE = """\
## Memory System (Session Startup + Hooks)

**On session start:** Read `memory/semantic.md` ONCE to load project context.

**On every turn:** The preprompt hook (`hooks/preprompt.txt`) handles reading `memory/working.md`.

**Task files:** Only load `/dev/[task]/*` files when actively working on that task.

**MCP efficiency:** Before calling any MCP tool to retrieve information, first check if that information might exist in `memory/semantic.md` or `dev/[task]/context.md` — local files are cheaper than remote MCP queries.

**Keep context minimal:** Do not speculatively load files "just in case".

**Mid-session drift:** If reasoning becomes uncertain or inconsistent with prior context, re-read `memory/semantic.md` before continuing.

**When a PR merges:** In addition to `semantic.md` and `DECISIONS.md`, check `{arch_file}` — move shipped capabilities to `memory/semantic.md` and remove them from the Vision section; append a supersession to `DECISIONS.md` then update or remove any invalidated Assumption. Planning details (tickets, checklists, phases) stay in planning docs, never in `{arch_file}`.

---

## Architecture vision

Before implementing a feature, read `{arch_file}`. It is the canonical record of architectural principles, load-bearing assumptions, and planned capabilities — not current build state (that lives in `memory/semantic.md`)."""


VALID_CAPTURE_LEVELS = frozenset(["response", "commit", "merge"])
DEFAULT_CAPTURE_LEVELS = ["response", "merge"]


def _normalize_capture_at(config: dict) -> list[str]:
    """Extract and validate memory.capture_at from config.

    Missing/null capture_at uses the backward-compatible default. An explicit
    empty list is valid and generates a warning-only hook.
    """
    memory = config.get("memory") or {}
    raw = memory.get("capture_at", DEFAULT_CAPTURE_LEVELS)

    if raw is None:
        return list(DEFAULT_CAPTURE_LEVELS)

    if isinstance(raw, str):
        raw = [raw]

    if not isinstance(raw, list):
        print(
            f"  Warning: memory.capture_at must be a list, got {type(raw).__name__}. "
            "Using default."
        )
        return list(DEFAULT_CAPTURE_LEVELS)

    result = []
    seen = set()
    for level in raw:
        if not isinstance(level, str):
            print(f"  Warning: skipping non-string capture level: {level!r}")
            continue
        normalized = level.strip().lower()
        if normalized not in VALID_CAPTURE_LEVELS:
            print(
                f"  Warning: unknown capture level {normalized!r} — valid: "
                f"{sorted(VALID_CAPTURE_LEVELS)}"
            )
            continue
        if normalized not in seen:
            result.append(normalized)
            seen.add(normalized)

    return result


def _build_stop_sh(capture_at: list[str], config: dict) -> str:
    """Generate stop.sh content based on normalized capture levels and config."""
    sem_mode = mode_for("memory/semantic.md", config)
    dec_mode = mode_for("DECISIONS.md", config)

    sem_reminder = (
        '  echo "- semantic.md: PROPOSE first, write only on approval"'
        if sem_mode == "review"
        else '  echo "- semantic.md: update directly; summarize changes"'
    )
    dec_reminder = (
        '  echo "- DECISIONS.md: PROPOSE first, write only on approval"'
        if dec_mode == "review"
        else '  echo "- DECISIONS.md: update directly; summarize changes"'
    )
    if not capture_at:
        return textwrap.dedent(
            """\
            #!/bin/bash
            # stop.sh — no capture levels configured
            """
        ) + GENERATED_BANNER_SH + "\n" + textwrap.dedent(
            """\
            set -euo pipefail
            echo "Warning: memory.capture_at is empty — no decision capture is configured."
            echo "Add response, commit, and/or merge to memory.capture_at in .agent/project.yaml."
            """
        )

    lines = [
        "#!/bin/bash",
        f"# stop.sh — capture levels: {', '.join(capture_at)}",
        GENERATED_BANNER_SH,
        "set -euo pipefail",
        "",
        "emit_memory_reminder() {",
        '  echo "Memory check — inspect diff and propose updates if significant:"',
        '  echo "- working.md: update current state (no approval needed)"',
        sem_reminder,
        dec_reminder,
        '  echo "- If intent unclear from diff, ask before proposing"',
        "}",
        "",
        'REPO_ROOT="$(git rev-parse --show-toplevel 2>/dev/null || echo .)"',
    ]

    if "response" in capture_at:
        lines += [
            "",
            "# response level — tracked changes relative to HEAD",
            'CHANGED="$(git -C "$REPO_ROOT" diff HEAD --name-only 2>/dev/null || true)"',
            'if [ -n "$CHANGED" ]; then',
            "  emit_memory_reminder",
            "fi",
        ]

    if "commit" in capture_at or "merge" in capture_at:
        lines += [
            "",
            "# commit / merge level — scan all commits since last hook run",
            'SENTINEL="$REPO_ROOT/.agent/.last_checked_commit"',
            'PREV_HEAD="$(cat "$SENTINEL" 2>/dev/null || true)"',
            'CURRENT_HEAD="$(git -C "$REPO_ROOT" rev-parse HEAD 2>/dev/null || true)"',
            "",
            'if [ -n "$PREV_HEAD" ] && [ -n "$CURRENT_HEAD" ] && [ "$CURRENT_HEAD" != "$PREV_HEAD" ]; then',
            "  HAS_COMMIT=false",
            "  HAS_MERGE=false",
            "",
            "  # Use range scan if PREV_HEAD is still an ancestor; fall back to HEAD only on rebase/reset",
            '  if git -C "$REPO_ROOT" merge-base --is-ancestor "$PREV_HEAD" "$CURRENT_HEAD" 2>/dev/null; then',
            '    RANGE_COMMITS="$(git -C "$REPO_ROOT" rev-list "$PREV_HEAD..$CURRENT_HEAD" 2>/dev/null || true)"',
            "  else",
            '    RANGE_COMMITS="$CURRENT_HEAD"',
            "  fi",
            "",
            '  for C in $RANGE_COMMITS; do',
            '    # rev-list --parents outputs: <sha> <p1> [<p2> ...]; wc -w - 1 = parent count',
            '    WORDS="$(git -C "$REPO_ROOT" rev-list --parents -n 1 "$C" 2>/dev/null | wc -w)"',
            '    PARENTS=$((WORDS - 1))',
            '    if [ "$PARENTS" -ge 2 ]; then HAS_MERGE=true; else HAS_COMMIT=true; fi',
            "  done",
        ]

        if "commit" in capture_at:
            lines += [
                "",
                '  if [ "$HAS_COMMIT" = "true" ]; then',
                "    emit_memory_reminder",
                "  fi",
            ]

        if "merge" in capture_at:
            lines += [
                "",
                '  if [ "$HAS_MERGE" = "true" ]; then',
                '    echo "Merge commit detected — review architectural impact:"',
                "    emit_memory_reminder",
                "  fi",
            ]

        lines += ["fi"]

        lines += [
            "",
            "# Update sentinel",
            'CURRENT_HEAD="$(git -C "$REPO_ROOT" rev-parse HEAD 2>/dev/null || true)"',
            'if [ -n "$CURRENT_HEAD" ]; then',
            "  mkdir -p \"$REPO_ROOT/.agent\"",
            '  echo "$CURRENT_HEAD" > "$SENTINEL"',
            "fi",
        ]

    return "\n".join(lines) + "\n"


def referenced_memory_files() -> list[str]:
    """Return the set of .md files this adapter's Memory Discipline references."""
    return [
        "memory/semantic.md",
        "memory/working.md",
        "DECISIONS.md",
        "dev/[task]/context.md",
    ]


def _build_preprompt(project_root: Path) -> str:
    """Read the preprompt template."""
    templates = project_root / ".agent" / "memory-kit" / "templates"
    return (templates / "preprompt.txt").read_text()


def generate(project_root: Path, config: dict) -> str:
    """Generate Claude Code configuration."""
    project = config["project"]
    mk_dir = project_root / ".agent" / "memory-kit"
    templates = mk_dir / "templates"

    # Write hooks/preprompt.txt
    hooks_dir = project_root / "hooks"
    hooks_dir.mkdir(exist_ok=True)
    preprompt_content = _build_preprompt(project_root)
    (hooks_dir / "preprompt.txt").write_text(preprompt_content)

    # Write hooks/stop.sh and make executable
    stop_path = hooks_dir / "stop.sh"
    capture_at = _normalize_capture_at(config)
    stop_path.write_text(_build_stop_sh(capture_at, config))
    stop_path.chmod(0o755)
    ensure_gitignored(project_root, ".agent/.last_checked_commit")

    # Generate .claude/settings.json
    claude_dir = project_root / ".claude"
    claude_dir.mkdir(exist_ok=True)
    settings_path = claude_dir / "settings.json"

    our_hooks = {
        "UserPromptSubmit": [
            {"hooks": [{"type": "command", "command": 'cat "$CLAUDE_PROJECT_DIR/hooks/preprompt.txt"'}]}
        ],
        "Stop": [
            {"hooks": [{"type": "command", "command": 'bash "$CLAUDE_PROJECT_DIR/hooks/stop.sh"'}]}
        ],
    }

    if settings_path.exists():
        try:
            existing = json.loads(settings_path.read_text())
        except (json.JSONDecodeError, OSError):
            existing = {}
    else:
        existing = {}

    existing.setdefault("hooks", {}).update(our_hooks)
    settings_path.write_text(json.dumps(existing, indent=2) + "\n")

    arch_file = config.get("architecture", {}).get("file", "vision.md")
    managed_content = MANAGED_CONTENT_TEMPLATE.format(arch_file=arch_file)

    # Project header — written once on first create, never regenerated
    header = f"# {project['name']} — Developer Guide\n\n**{project['name']}** is {project['description']}"

    claude_md_status = write_managed_section(
        project_root / "CLAUDE.md", header, managed_content, "CLAUDE.md"
    )

    return (
        "Claude Code configuration generated:\n"
        f"{claude_md_status}\n"
        "  - .claude/settings.json (hooks merged)\n"
        "  - hooks/preprompt.txt\n"
        "  - hooks/stop.sh"
    )


# ── Check mode ────────────────────────────────────────────────────────────────


def check(project_root: Path, config: dict) -> list[str]:
    """Return drift diffs for all managed/generated files (empty if no drift)."""
    diffs = []
    arch_file = config.get("architecture", {}).get("file", "vision.md")

    # CLAUDE.md — sentinel-managed
    managed_content = MANAGED_CONTENT_TEMPLATE.format(arch_file=arch_file)
    r = check_managed_section(
        project_root / "CLAUDE.md", managed_content, "CLAUDE.md"
    )
    if r:
        diffs.append(r)

    # hooks/preprompt.txt — fully generated
    preprompt_expected = _build_preprompt(project_root)
    r = check_fully_generated(
        project_root / "hooks" / "preprompt.txt",
        preprompt_expected,
        "hooks/preprompt.txt",
    )
    if r:
        diffs.append(r)

    # hooks/stop.sh — fully generated
    capture_at = _normalize_capture_at(config)
    stop_expected = _build_stop_sh(capture_at, config)
    r = check_fully_generated(
        project_root / "hooks" / "stop.sh",
        stop_expected,
        "hooks/stop.sh",
    )
    if r:
        diffs.append(r)

    # .claude/settings.json — verify required hooks match expected commands
    settings_path = project_root / ".claude" / "settings.json"
    if not settings_path.exists():
        diffs.append(".claude/settings.json: file does not exist (not yet generated)")
    else:
        try:
            actual = json.loads(settings_path.read_text())
        except (json.JSONDecodeError, OSError):
            diffs.append(".claude/settings.json: invalid JSON")
            return diffs

        expected_hooks = {
            "UserPromptSubmit": [
                {"hooks": [{"type": "command", "command": 'cat "$CLAUDE_PROJECT_DIR/hooks/preprompt.txt"'}]}
            ],
            "Stop": [
                {"hooks": [{"type": "command", "command": 'bash "$CLAUDE_PROJECT_DIR/hooks/stop.sh"'}]}
            ],
        }
        actual_hooks = actual.get("hooks", {})

        for event, configs in expected_hooks.items():
            if event not in actual_hooks:
                diffs.append(f".claude/settings.json: missing required hook '{event}'")
                continue
            if actual_hooks[event] != configs:
                diffs.append(
                    f".claude/settings.json: hook '{event}' commands differ from expected\n"
                    f"  expected: {configs}\n"
                    f"  actual:   {actual_hooks[event]}"
                )

    return diffs
